package com.hospital.management.dao.impl;
import com.hospital.management.dao.PatientDao;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.util.*;
/** Oracle JDBC patient persistence; never selects account password hashes. */
public class PatientDaoImpl implements PatientDao{private static final String COL="p.PATIENT_ID,p.USER_ID,p.PATIENT_NUMBER,p.FIRST_NAME,p.LAST_NAME,p.DATE_OF_BIRTH,p.GENDER,p.BLOOD_GROUP,p.PHONE,p.EMAIL,p.ADDRESS,p.EMERGENCY_CONTACT_NAME,p.EMERGENCY_CONTACT_PHONE,p.STATUS AS PATIENT_STATUS,u.USERNAME,u.STATUS AS USER_STATUS,p.CREATED_AT,p.UPDATED_AT ",FROM=" FROM PATIENTS p LEFT JOIN USERS u ON u.USER_ID=p.USER_ID ",FILTER=" WHERE (? IS NULL OR UPPER(p.PATIENT_NUMBER) LIKE ? ESCAPE '\\' OR UPPER(p.FIRST_NAME) LIKE ? ESCAPE '\\' OR UPPER(p.LAST_NAME) LIKE ? ESCAPE '\\' OR UPPER(p.FIRST_NAME||' '||p.LAST_NAME) LIKE ? ESCAPE '\\' OR UPPER(p.PHONE) LIKE ? ESCAPE '\\' OR UPPER(p.EMAIL) LIKE ? ESCAPE '\\' OR UPPER(u.USERNAME) LIKE ? ESCAPE '\\' OR UPPER(p.BLOOD_GROUP) LIKE ? ESCAPE '\\' OR UPPER(p.STATUS) LIKE ? ESCAPE '\\') AND (? IS NULL OR p.STATUS=?) ";
 public Optional<Patient> findById(Long id)throws SQLException{return id==null?Optional.empty():one("SELECT "+COL+FROM+" WHERE p.PATIENT_ID=?",id);}public Optional<Patient> findByPatientNumber(String n)throws SQLException{return n==null?Optional.empty():one("SELECT "+COL+FROM+" WHERE UPPER(p.PATIENT_NUMBER)=UPPER(?)",n.trim());}private Optional<Patient> one(String sql,Object v)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(sql)){s.setObject(1,v);try(ResultSet r=s.executeQuery()){return r.next()?Optional.of(map(r)):Optional.empty();}}}
 public Page<Patient> findAll(PageRequest q,String status)throws SQLException{List<Patient>x=new ArrayList<>();String sql="SELECT "+COL+FROM+FILTER+" ORDER BY p.FIRST_NAME,p.LAST_NAME,p.PATIENT_ID OFFSET ? ROWS FETCH NEXT ? ROWS ONLY";try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(sql)){int i=bind(s,q.getSearchTerm(),norm(status));s.setInt(i++,q.getOffset());s.setInt(i,q.getPageSize());try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}}return new Page<>(x,q.getPageNumber(),q.getPageSize(),count(q.getSearchTerm(),status));}public long count(String search,String status)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT COUNT(1)"+FROM+FILTER)){bind(s,search,norm(status));try(ResultSet r=s.executeQuery()){r.next();return r.getLong(1);}}}
 private int bind(PreparedStatement s,String search,String status)throws SQLException{String t=search==null?"":search.trim(),p="%"+t.toUpperCase(Locale.ROOT).replace("\\","\\\\").replace("%","\\%").replace("_","\\_")+"%";int i=1;s.setString(i++,t.isEmpty()?null:p);for(int n=0;n<9;n++)s.setString(i++,p);s.setString(i++,status);s.setString(i++,status);return i;}
 public long createPatientRecord(Connection c,Patient p)throws SQLException{String sql="INSERT INTO PATIENTS(USER_ID,PATIENT_NUMBER,FIRST_NAME,LAST_NAME,DATE_OF_BIRTH,GENDER,BLOOD_GROUP,PHONE,EMAIL,ADDRESS,EMERGENCY_CONTACT_NAME,EMERGENCY_CONTACT_PHONE,STATUS) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)";try(PreparedStatement s=c.prepareStatement(sql,new String[]{"PATIENT_ID"})){if(p.getUserId()==null)s.setNull(1,Types.NUMERIC);else s.setLong(1,p.getUserId());bindPatient(s,p,2);s.executeUpdate();try(ResultSet k=s.getGeneratedKeys()){if(k.next())return k.getLong(1);}throw new SQLException("No generated patient identifier returned");}}
 public boolean updatePatientRecord(Connection c,Patient p)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE PATIENTS SET PATIENT_NUMBER=?,FIRST_NAME=?,LAST_NAME=?,DATE_OF_BIRTH=?,GENDER=?,BLOOD_GROUP=?,PHONE=?,EMAIL=?,ADDRESS=?,EMERGENCY_CONTACT_NAME=?,EMERGENCY_CONTACT_PHONE=?,STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE PATIENT_ID=?")){int i=bindPatient(s,p,1);s.setLong(i,p.getPatientId());return s.executeUpdate()==1;}}private int bindPatient(PreparedStatement s,Patient p,int i)throws SQLException{s.setString(i++,p.getPatientNumber());s.setString(i++,p.getFirstName());s.setString(i++,p.getLastName());s.setDate(i++,java.sql.Date.valueOf(p.getDateOfBirth()));s.setString(i++,p.getGender());s.setString(i++,p.getBloodGroup());s.setString(i++,p.getPhone());s.setString(i++,p.getEmail());s.setString(i++,p.getAddress());s.setString(i++,p.getEmergencyContactName());s.setString(i++,p.getEmergencyContactPhone());s.setString(i++,p.getStatus());return i;}
 public boolean linkUserAccount(Connection c,Long id,Long uid)throws SQLException{return upd(c,"UPDATE PATIENTS SET USER_ID=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE PATIENT_ID=? AND USER_ID IS NULL",uid,id);}public boolean updatePatientStatus(Connection c,Long id,String status)throws SQLException{return upd(c,"UPDATE PATIENTS SET STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE PATIENT_ID=?",norm(status),id);}private boolean upd(Connection c,String sql,Object a,Long id)throws SQLException{try(PreparedStatement s=c.prepareStatement(sql)){s.setObject(1,a);s.setLong(2,id);return s.executeUpdate()==1;}}
 public boolean existsByPatientNumber(String n)throws SQLException{return exists("SELECT 1 FROM PATIENTS WHERE UPPER(PATIENT_NUMBER)=UPPER(?) FETCH FIRST 1 ROW ONLY",n,null);}public boolean existsByPatientNumberExcludingId(String n,Long id)throws SQLException{return exists("SELECT 1 FROM PATIENTS WHERE UPPER(PATIENT_NUMBER)=UPPER(?) AND PATIENT_ID<>? FETCH FIRST 1 ROW ONLY",n,id);}private boolean exists(String sql,String n,Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(sql)){s.setString(1,n);if(id!=null)s.setLong(2,id);try(ResultSet r=s.executeQuery()){return r.next();}}}public boolean hasFutureAppointments(Long id)throws SQLException{return byId("SELECT 1 FROM APPOINTMENTS WHERE PATIENT_ID=? AND TRUNC(APPOINTMENT_DATE)>=TRUNC(SYSDATE) AND STATUS IN('SCHEDULED','CONFIRMED') FETCH FIRST 1 ROW ONLY",id);}public boolean hasActiveAdmission(Long id)throws SQLException{return byId("SELECT 1 FROM ADMISSIONS WHERE PATIENT_ID=? AND STATUS='ADMITTED' FETCH FIRST 1 ROW ONLY",id);}private boolean byId(String sql,Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(sql)){s.setLong(1,id);try(ResultSet r=s.executeQuery()){return r.next();}}}
 private String norm(String s){if(s==null||s.isBlank())return null;String n=s.trim().toUpperCase(Locale.ROOT);if(!Set.of("ACTIVE","INACTIVE").contains(n))throw new IllegalArgumentException("Invalid patient status");return n;}private Patient map(ResultSet r)throws SQLException{Patient p=new Patient();p.setPatientId(r.getLong("PATIENT_ID"));long uid=r.getLong("USER_ID");p.setUserId(r.wasNull()?null:uid);p.setPatientNumber(r.getString("PATIENT_NUMBER"));p.setFirstName(r.getString("FIRST_NAME"));p.setLastName(r.getString("LAST_NAME"));java.sql.Date d=r.getDate("DATE_OF_BIRTH");p.setDateOfBirth(d==null?null:d.toLocalDate());p.setGender(r.getString("GENDER"));p.setBloodGroup(r.getString("BLOOD_GROUP"));p.setPhone(r.getString("PHONE"));p.setEmail(r.getString("EMAIL"));p.setAddress(r.getString("ADDRESS"));p.setEmergencyContactName(r.getString("EMERGENCY_CONTACT_NAME"));p.setEmergencyContactPhone(r.getString("EMERGENCY_CONTACT_PHONE"));p.setStatus(r.getString("PATIENT_STATUS"));p.setUsername(r.getString("USERNAME"));p.setUserStatus(r.getString("USER_STATUS"));Timestamp c=r.getTimestamp("CREATED_AT"),u=r.getTimestamp("UPDATED_AT");p.setCreatedAt(c==null?null:c.toLocalDateTime());p.setUpdatedAt(u==null?null:u.toLocalDateTime());return p;}}
